// Converte o binário para texto markdown
const item = $input.first();
const fileName = $('Google Drive — Pasta Oficializar').item.json.name || 'documento';
const mimeType = $('Google Drive — Pasta Oficializar').item.json.mimeType || '';
const modifiedTime = $('Google Drive — Pasta Oficializar').item.json.modifiedTime || new Date().toISOString();

let content = '';
if (item.binary?.data) {
  content = Buffer.from(item.binary.data.data, 'base64').toString('utf-8');
} else if (item.json?.data) {
  content = item.json.data;
}

// Divide em chunks de ~2000 chars para embeddings
const chunkSize = 2000;
const overlap = 200;
const chunks = [];
for (let i = 0; i < content.length; i += chunkSize - overlap) {
  chunks.push(content.slice(i, i + chunkSize));
}

return chunks.map((chunk, idx) => ({
  json: {
    title: `${fileName} [parte ${idx + 1}/${chunks.length}]`,
    content: chunk,
    source: 'google_drive',
    source_url: `gdrive://${$('Google Drive — Pasta Oficializar').item.json.id}`,
    tags: ['ssot', 'oficializar', fileName.toLowerCase().replace(/\s+/g, '-')],
    modified_time: modifiedTime
  }
}));
